mapper.select:
SELECT ID, MEMBER_INQUIRY_TYPE, MEMBER_NAME, MEMBER_EMAIL, TO_CHAR(CREATED_DATE, 'YYYY-MM-DD') AS CREATED_DATE,
       MEMBER_INQUIRY_STATUS, MEMBER_INQUIRY_DETAIL
    FROM
        (
            SELECT ID, ROWNUM R, MEMBER_INQUIRY_TYPE, MEMBER_NAME, MEMBER_EMAIL, CREATED_DATE, MEMBER_INQUIRY_STATUS, MEMBER_INQUIRY_DETAIL
                FROM
                (
            SELECT MI.ID, MEMBER_INQUIRY_TYPE, MEMBER_NAME, MEMBER_EMAIL, MI.CREATED_DATE, MEMBER_INQUIRY_STATUS, MEMBER_INQUIRY_DETAIL
           FROM TBL_MEMBER_INQUIRY MI JOIN TBL_MEMBER M
            ON MI.MEMBER_ID = M.ID
        WHERE M.ID IS NOT NULL

         AND MEMBER_INQUIRY_STATUS = #{status}


        AND MEMBER_NAME LIKE '%' || #{normalInquiryKeyword} || '%'


        AND CEIL(SYSDATE - TO_DATE(MI.CREATED_DATE))  <= #{date}

    ORDER BY ID DESC
           )

        WHERE ROWNUM <= ${endRow}

    )

        WHERE R >= ${startRow}

mapper.update:
UPDATE TBL_MEMBER_INQUIRY
SET MEMBER_INQUIRY_STATUS = #{memberInquiryStatus}
WHERE ID = #{id}

mapper.select:
SELECT COUNT(*)
FROM
    (
SELECT ID, MEMBER_INQUIRY_TYPE, MEMBER_NAME, MEMBER_EMAIL, CREATED_DATE, MEMBER_INQUIRY_STATUS, MEMBER_INQUIRY_DETAIL, MEMBER_RECENT_LOGIN
FROM
(
SELECT ID, ROWNUM R, MEMBER_INQUIRY_TYPE, MEMBER_NAME, MEMBER_EMAIL,
       TO_CHAR(CREATED_DATE, 'YYYY-MM-DD') AS CREATED_DATE, MEMBER_INQUIRY_STATUS, MEMBER_INQUIRY_DETAIL, TO_CHAR(MEMBER_RECENT_LOGIN, 'YYYY-MM-DD') AS MEMBER_RECENT_LOGIN
FROM
(
SELECT MI.ID, MEMBER_INQUIRY_TYPE, MEMBER_NAME, MEMBER_EMAIL, MI.CREATED_DATE, MEMBER_INQUIRY_STATUS, MEMBER_INQUIRY_DETAIL, M.MEMBER_RECENT_LOGIN
FROM TBL_MEMBER_INQUIRY MI JOIN TBL_MEMBER M
ON MI.MEMBER_ID = M.ID
WHERE M.ID IS NOT NULL

    AND MEMBER_INQUIRY_TYPE = #{status}


    AND MEMBER_NAME LIKE '%' || #{normalInquiryKeyword} || '%'


    AND CEIL(SYSDATE - TO_DATE(MEMBER_RECENT_LOGIN))  <= #{date}

ORDER BY ID DESC
)

    WHERE ROWNUM <= ${endRow}

)

    WHERE R >= ${startRow}

    )
